#include <bits/stdc++.h>
using namespace std;
int gcd(int m,int n){
    while(n!=0){
        int tmp=n;
        n=m%n;
        m=tmp;
    }
    return m;
}
int main(){
    long long a[3],b,c;
    cin>>a[0]>>a[1]>>a[2];
    b=gcd(a[0],a[1]);
    c=gcd(b,a[2]);
    cout<<c;
    return 0;
}
